('VMC_2021_parent_inventory_1', 'VMC', 2021, 'parent', 'Công cụ, dụng cụ', 'raw_material', 185902578.0, 0.0, 'Công cụ, dụng cụ tồn kho cuối kỳ'),
('VMC_2021_parent_inventory_2', 'VMC', 2021, 'parent', 'Chi phí sản xuất, kinh doanh dở dang', 'construction_in_progress', 154168583153.0, 0.0, 'Chi phí sản xuất, kinh doanh dở dang tăng 25,6% so với đầu năm (122.685.830.096 VND), phản ánh quy mô hoạt động xây lắp và sản xuất bê tông mở rộng'),
('VMC_2021_parent_inventory_3', 'VMC', 2021, 'parent', 'Công trình san nền cho diện tích 1,7ha thuộc lô E9, đường Phạm Hùng', 'construction_in_progress', 9001562600.0, 0.0, 'Chi phí đầu tư xây dựng hạ tầng kỹ thuật theo Quyết định 1856/QĐ-UB, đang trong quá trình thanh quyết toán với Sở Tài chính Hà Nội và các nhà đầu tư thứ cấp'),
('VMC_2021_parent_inventory_4', 'VMC', 2021, 'parent', 'Trạm bê tông Đồng Nai', 'construction_in_progress', 1033535916.0, 0.0, 'Chi phí xây dựng cơ bản dở dang phát sinh trong năm'),
('VMC_2021_consolidated_inventory_0', 'VMC', 2021, 'consolidated', 'Nguyên liệu, vật liệu', 'raw_material', 6084260273.0, 0.0, NULL),
('VMC_2021_consolidated_inventory_1', 'VMC', 2021, 'consolidated', 'Công cụ, dụng cụ', 'raw_material', 185902578.0, 0.0, NULL),
('VMC_2021_consolidated_inventory_2', 'VMC', 2021, 'consolidated', 'Chi phí sản xuất, kinh doanh dở dang', 'construction_in_progress', 180183544732.0, 0.0, 'Bao gồm dự án Công trình san nền cho diện tích 1,7ha thuộc lô E9, đường Phạm Hùng (trị giá 9.001.562.600 VND) và chi phí sản xuất kinh doanh dở dang khác'),
('VMC_2021_consolidated_inventory_3', 'VMC', 2021, 'consolidated', 'Chi phí sản xuất kinh doanh dở dang dài hạn - Công trình san nền lô E9 đường Phạm Hùng', 'construction_in_progress', 9001562600.0, 0.0, 'Công trình san nền cho diện tích 1,7ha thuộc lô E9, đường Phạm Hùng theo Quyết định số 1856/QĐ-UB ngày 2/4/2004 của UBND TP Hà Nội. Công ty đang trong quá trình làm việc với Sở Tài chính Hà Nội và các nhà đầu tư thứ phát để quyết toán giá trị chi phí đã đầu tư.'),
('VMC_2021_consolidated_inventory_4', 'VMC', 2021, 'consolidated', 'Chi phí xây dựng cơ bản dở dang - Trạm bê tông Đồng Nai', 'construction_in_progress', 1033535916.0, 0.0, NULL),
('VMC_2021_consolidated_inventory_5', 'VMC', 2021, 'consolidated', 'Phải thu chi phí đầu tư Dự án Khu đô thị Cao Xanh – Hà Khánh D', 'real_estate_project', 24549196556.0, 0.0, 'Dự án xây dựng và kinh doanh hạ tầng Khu đô thị Cao Xanh – Hà Khánh D, phường Hà Khánh, thành phố Hạ Long. Dự án bị thu hồi năm 2012. Các bên đã thống nhất phương án xác định giá trị chi phí đầu tư hoàn trả là 31.875.763.848 VND, đang trong quá trình hoàn thiện thủ tục pháp lý.'),
('VMC_2020_parent_inventory_0', 'VMC', 2020, 'parent', 'Chi phí sản xuất kinh doanh dở dang', 'construction_in_progress', 122685830096.0, 327925146.0, 'Bao gồm giá trị của các công trình xây dựng dở dang: Hạ tầng khu Cao Ngạn, Thái Nguyên (35.987.621.400 VND); Khoan cọc nhồi tháp ven sông Đà Nẵng (22.938.959.051 VND); Tường vây, tầng hầm PA Tower Đà Nẵng (9.121.302.718 VND); Cao tốc Đà Nẵng – Quảng Ngãi (6.349.025.402 VND); Đài móng tầng hầm ADG Garden (5.409.537.027 VND); và các dự án khác.'),
('VMC_2020_parent_inventory_1', 'VMC', 2020, 'parent', 'Chi phí xây dựng cơ bản dở dang dài hạn', 'construction_in_progress', 1386043637.0, 0.0, 'Gồm Mỏ đá Phú Minh – Kỳ Sơn – Hòa Bình (1.386.043.637 VND) và Trạm bê tông Vân Phong – Nha Trang (đã giảm xuống 0).'),
('VMC_2020_parent_inventory_2', 'VMC', 2020, 'parent', 'Nguyên liệu, vật liệu', 'raw_material', 7049115170.0, 0.0, 'Nguyên vật liệu phục vụ sản xuất kinh doanh.'),
