('VLP_2020_consolidated_inventory_1', 'VLP', 2020, 'consolidated', 'Chi phí xây dựng cơ bản dở dang', 'construction_in_progress', 1045909090.0, 0.0, 'Chi phí mua xe Fortuner 7 chỗ và chi phí thẩm định mua xe bồn'),
