('VLP_2018_consolidated_inventory_1', 'VLP', 2018, 'consolidated', 'Chi phí sản xuất kinh doanh dở dang', 'construction_in_progress', 168898500.0, 0.0, 'Chi phí sản xuất kinh doanh dở dang, liên quan đến các dịch vụ/công trình chưa hoàn thành'),
('VLP_2017_consolidated_inventory_0', 'VLP', 2017, 'consolidated', 'Nguyên liệu, vật liệu', 'raw_material', 41266000.0, 0.0, 'Nguyên liệu, vật liệu tồn kho cuối năm'),
('VLP_2017_consolidated_inventory_1', 'VLP', 2017, 'consolidated', 'Các công trình trồng hoa, trang trí', 'construction_in_progress', 54910000.0, 0.0, 'Chi phí sản xuất kinh doanh dở dang - công trình trồng hoa, trang trí'),
('VLP_2017_consolidated_inventory_2', 'VLP', 2017, 'consolidated', 'Lắp đặt hệ thống đèn trang trí', 'construction_in_progress', 153138500.0, 0.0, 'Chi phí sản xuất kinh doanh dở dang - lắp đặt hệ thống đèn trang trí'),
('VLG_2025_consolidated_inventory_0', 'VLG', 2025, 'consolidated', 'Dự án mở rộng Cảng nội địa ICD Lào Cai', 'construction_in_progress', 1241512034.0, 0.0, 'Chi phí xây dựng cơ bản dở dang, dự án đã hoàn thành giai đoạn I, II và đưa vào khai thác. Giai đoạn III và IV đang lập hồ sơ điều chỉnh.'),
('VLG_2024_consolidated_inventory_0', 'VLG', 2024, 'consolidated', 'ICD Lao Cai Inland Port expansion project', 'construction_in_progress', 1241512034.0, 0.0, 'Dự án mở rộng cảng cạn ICD Lao Cai (giai đoạn III và IV), đang trong giai đoạn chuẩn bị hồ sơ điều chỉnh tổng thể dự án, chi phí bao gồm lập báo cáo nghiên cứu tiền khả thi và đánh giá tác động môi trường. Các giai đoạn I và II đã hoàn thành và đưa vào vận hành.'),
('VLG_2022_consolidated_inventory_0', 'VLG', 2022, 'consolidated', 'Dự án Khu dịch vụ hậu cần cảng Cái Lân', 'real_estate_project', 34003303719.0, NULL, 'Tổng diện tích 185,913 m² tại Hạ Long, Quảng Ninh. Triển khai từ 2009. Công ty đã dừng hợp tác kinh doanh với Công ty TNHH Tổ chức nhà Quốc gia Quảng Ninh và Công ty TNHH Happy Land Việt Nhật, đang tìm kiếm đối tác mới. Chi phí bao gồm giải phóng mặt bằng, bồi thường đất và chi phí khảo sát, tư vấn.'),
('VLG_2022_consolidated_inventory_1', 'VLG', 2022, 'consolidated', 'Dự án mở rộng Cảng nội địa ICD Lào Cai', 'construction_in_progress', 1235179034.0, NULL, 'Tổng diện tích 100,172 m², tổng mức đầu tư 219.051 tỷ VND. Giai đoạn I, II đã hoàn thành đưa vào khai thác. Giai đoạn III, IV đang lập hồ sơ điều chỉnh tổng thể dự án theo yêu cầu của BQL Khu kinh tế tỉnh Lào Cai.'),
('VLG_2021_consolidated_inventory_0', 'VLG', 2021, 'consolidated', 'Dự án Khu dịch vụ hậu cần cảng Cái Lân', 'construction_in_progress', 30764267059.0, NULL, 'Chi phí đầu tư vào dự án, bao gồm giải phóng mặt bằng, bồi thường đất, khảo sát, tư vấn thiết kế. Công ty đang tìm đối tác hợp tác kinh doanh trên diện tích 128.524,8 m².'),
('VLG_2021_consolidated_inventory_1', 'VLG', 2021, 'consolidated', 'Dự án mở rộng Cảng nội địa ICD Lào Cai', 'construction_in_progress', 475005034.0, NULL, 'Dự án đã hoàn thành giai đoạn I, II và đưa vào khai thác. Giai đoạn III, IV đang trong quá trình điều chỉnh dự án và hoàn thiện hồ sơ.'),
('VLG_2021_consolidated_inventory_2', 'VLG', 2021, 'consolidated', 'Dự án kho tại khu công nghệ cao Láng Hòa Lạc', 'construction_in_progress', 324126585.0, NULL, 'Chi phí khảo sát địa hình ban đầu. Dự án đã được chuyển giao cho Công ty Cổ phần Vinalines Hòa Lạc Logistics, Công ty đang làm việc để hoàn trả kinh phí.'),
('VLG_2020_consolidated_inventory_0', 'VLG', 2020, 'consolidated', 'Dự án Khu dịch vụ hậu cần cảng Cái Lân', 'real_estate_project', 30691539787.0, 0.0, 'Chi phí đầu tư vào dự án Khu dịch vụ hậu cần cảng Cái Lân, bao gồm chi phí giải phóng mặt bằng, bồi thường đất và các chi phí khác. Dự án được triển khai từ 2009, hiện đang tìm kiếm đối tác hợp tác kinh doanh để thu hồi chi phí.'),
('VLG_2020_consolidated_inventory_1', 'VLG', 2020, 'consolidated', 'Dự án mở rộng Cảng nội địa ICD Lào Cai', 'construction_in_progress', 475005034.0, 0.0, 'Chi phí đầu tư vào dự án Đầu tư xây dựng cảng nội địa ICD Lào Cai. Dự án đã hoàn thành giai đoạn I và II, đang tiến hành lập hồ sơ điều chỉnh tổng thể cho giai đoạn III và IV.'),
('VLG_2020_consolidated_inventory_2', 'VLG', 2020, 'consolidated', 'Dự án kho tại khu công nghệ cao Láng Hòa Lạc', 'construction_in_progress', 324126585.0, 0.0, 'Chi phí khảo sát địa hình ban đầu cho dự án, đã được chuyển giao cho Công ty Cổ phần Vinalines Hòa Lạc Logistics, hiện đang làm việc để hoàn trả phần kinh phí này.'),
('VLG_2019_consolidated_inventory_0', 'VLG', 2019, 'consolidated', 'Dự án Cảng Cái Lân', 'construction_in_progress', 30691539787.0, NULL, 'Chi phí xây dựng cơ bản dở dang tại Quảng Ninh'),
('VLG_2019_consolidated_inventory_1', 'VLG', 2019, 'consolidated', 'Dự án mở rộng Cảng nội địa ICD Lào Cai', 'construction_in_progress', 475005034.0, NULL, 'Chi phí xây dựng cơ bản dở dang'),
('VLG_2019_consolidated_inventory_2', 'VLG', 2019, 'consolidated', 'Dự án kho tại khu công nghệ cao Láng Hòa Lạc', 'construction_in_progress', 324126585.0, NULL, 'Chi phí xây dựng cơ bản dở dang'),
('VLG_2019_consolidated_inventory_3', 'VLG', 2019, 'consolidated', 'Dự án kho bãi Container Logistics Quảng Ninh', 'construction_in_progress', 0.0, NULL, 'Giảm từ 1.569.066.632 đồng xuống 0 trong năm 2019'),
('VLG_2018_consolidated_inventory_0', 'VLG', 2018, 'consolidated', 'Dự án Cảng Cái Lân', 'construction_in_progress', 28866169519.0, 0.0, 'Dự án cơ bản đã hoàn thành xong công tác giải phóng mặt bằng. Hiện tại Công ty đang tích cực tìm kiếm đối tác để hợp tác thực hiện dự án.'),
('VLG_2018_consolidated_inventory_1', 'VLG', 2018, 'consolidated', 'Dự án mở rộng Cảng nội địa ICD Lào Cai', 'construction_in_progress', 475005034.0, 0.0, NULL);
