('VIW_2025_consolidated_inventory_0', 'VIW', 2025, 'consolidated', 'Nguyên liệu, vật liệu', 'raw_material', 24691260872.0, 361067058.0, 'Vật tư tồn kho tại 31/12/2025 là các vật tư, hàng hóa như ống gang, ống thép, cút, bích, tê... phục vụ hoạt động thi công hệ thống cấp thoát nước. Có một số vật tư không sử dụng trong nhiều năm, đề xuất thanh lý khoảng 8,56 tỷ đồng.'),
('VIW_2025_consolidated_inventory_1', 'VIW', 2025, 'consolidated', 'Công cụ, dụng cụ', 'raw_material', 322918109.0, 0.0, NULL);
INSERT OR REPLACE INTO `inventories_and_projects` (`id`, `ticker`, `year`, `report_type`, `item_name`, `item_type`, `value`, `provision`, `description`) VALUES
('VIW_2025_consolidated_inventory_2', 'VIW', 2025, 'consolidated', 'Chi phí sản xuất kinh doanh dở dang', 'construction_in_progress', 512664008438.0, 611457351.0, 'Chi phí dở dang liên quan đến các hợp đồng xây dựng tồn đọng kéo dài. Công ty đang thực hiện đối chiếu để quyết toán. Hội đồng quản trị đã chỉ đạo xây dựng kế hoạch xử lý từ năm 2019 nhưng kết quả chưa đạt.'),
('VIW_2025_consolidated_inventory_3', 'VIW', 2025, 'consolidated', 'Thành phẩm', 'finished_goods', 244223908.0, 0.0, NULL),
('VIW_2025_consolidated_inventory_4', 'VIW', 2025, 'consolidated', 'Hàng hoá', 'finished_goods', 111494199.0, 0.0, NULL),
('VIW_2025_consolidated_inventory_5', 'VIW', 2025, 'consolidated', 'Hàng gửi bán', 'finished_goods', 146016595.0, 0.0, NULL),
('VIW_2025_consolidated_inventory_6', 'VIW', 2025, 'consolidated', 'Dự án khu phức hợp Quận 9 - TP. Hồ Chí Minh', 'construction_in_progress', 15854386396.0, 0.0, NULL),
('VIW_2025_consolidated_inventory_7', 'VIW', 2025, 'consolidated', 'Dự án tổ hợp chung cư Hạ Đình - Thanh Xuân', 'real_estate_project', 24059249052.0, 0.0, 'Dự án theo hợp đồng hợp tác đầu tư với Công ty TNHH Tiến Đạt Phát. Tổng công ty góp vốn bằng quyền thuê đất và chi phí tính đến 31/12/2014. Dự án đang trong giai đoạn thực hiện thủ tục pháp lý.'),
('VIW_2025_consolidated_inventory_8', 'VIW', 2025, 'consolidated', 'Dự án xây dựng văn phòng cho thuê tại 52 Quốc Tử Giám', 'real_estate_project', 8784539294.0, 0.0, 'Dự án xây dựng văn phòng làm việc, văn phòng cho thuê và bán. Tổng vốn đầu tư 154.254.761.000 đồng. Dự án đang trong giai đoạn thực hiện thủ tục pháp lý.'),
('VIW_2025_consolidated_inventory_9', 'VIW', 2025, 'consolidated', 'Dự án Khu chung cư và văn phòng Trung Văn Tử Liêm', 'real_estate_project', 3218245846.0, 0.0, 'Dự án xây dựng tổ hợp nhà ở để bán kết hợp văn phòng và dịch vụ thương mại. Dự án đã nghiệm thu đưa vào sử dụng từ tháng 06/2019, đang trong giai đoạn thẩm tra, quyết toán.'),
('VIW_2025_consolidated_inventory_10', 'VIW', 2025, 'consolidated', 'Dự án Hệ thống cấp nước Khu vực Bắc Sông Hồng (Nhà máy nước Sông Đường)', 'construction_in_progress', 3724101701.0, 0.0, 'Theo Công văn số 264/TTg-KTN, dự án được chuyển giao cho Công ty TNHH MTV nước sạch Hà Nội (Hawaco). Đến nay, hai bên chưa thực hiện thủ tục bàn giao số liệu tài chính.'),
('VIW_2025_consolidated_inventory_11', 'VIW', 2025, 'consolidated', 'Các dự án khác', 'construction_in_progress', 7958134417.0, 0.0, NULL),
